    }
  }
}

query GetActivities($filters: ActivityFilterInput) {
  activities {
    activities(filters: $filters) {
      items {
        id
        serviceType
        actionType
        status
        resultCount
        createdAt
      }
      total
      limit
      offset
      hasNext
      hasPrevious
    }
  }
}

query GetActivityStats($filters: ActivityStatsInput) {
  activities {
    activityStats(filters: $filters) {
      totalActivities
      byServiceType
      byActionType
      byStatus
      recentActivities
    }
  }
}

input ActivityStatsInput {
  startDate: DateTime
  endDate: DateTime
}

